#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
fix-cycling-photos-i18n.py - Ajoute photos riders + logos teams + i18n FR/EN.

Usage:
    cd <repo-pariscore>
    python fix-cycling-photos-i18n.py
"""
import base64
import json
import os
import sys

_DATA_B64 = ""
DATA = json.loads(base64.b64decode(_DATA_B64).decode("utf-8"))
FILES_BASE64 = DATA["files"]
PATCHES = DATA["patches"]


def main():
    if not os.path.exists("pariscore.html"):
        print("ERREUR: pariscore.html non trouve.")
        sys.exit(1)

    print("=== Creation des fichiers (scripts + data + images + cyclingService.js) ===")
    for path, b64 in FILES_BASE64.items():
        dirpath = os.path.dirname(path)
        if dirpath:
            os.makedirs(dirpath, exist_ok=True)
        content = base64.b64decode(b64)
        with open(path, "wb") as f:
            f.write(content)
        print("  OK " + path + " (" + str(len(content)) + " bytes)")

    for fname, patches_key in [("pariscore.js", "pariscore_js"), ("server.js", "server_js"), ("pariscore.html", "pariscore_html")]:
        print()
        print("=== Patch " + fname + " ===")
        with open(fname, "r", encoding="utf-8") as f:
            content = f.read()
        for i, patch in enumerate(PATCHES[patches_key]):
            old, new = patch["old"], patch["new"]
            if old in content:
                content = content.replace(old, new, 1)
                print("  OK Patch " + str(i+1) + " applique")
            elif new in content:
                print("  WARN Patch " + str(i+1) + " deja applique")
            else:
                print("  FAIL Patch " + str(i+1) + " anchor non trouve!")
                sys.exit(1)
        with open(fname, "w", encoding="utf-8") as f:
            f.write(content)

    print()
    print("=== Ajout cles i18n cyc.* dans locales ===")
    for lang_file, new_keys in [("locales/fr.json", PATCHES["locales_fr_new_keys"]), ("locales/en.json", PATCHES["locales_en_new_keys"])]:
        with open(lang_file, "r", encoding="utf-8") as f:
            d = json.load(f)
        added = 0
        for k, v in new_keys.items():
            if k not in d:
                d[k] = v
                added += 1
        with open(lang_file, "w", encoding="utf-8") as f:
            json.dump(d, f, ensure_ascii=False, indent=2)
        print("  OK " + lang_file + " : " + str(added) + " cles ajoutees")

    print()
    print("=== TERMINE ===")
    print()
    print("Prochaines etapes :")
    print('  1. git add -A')
    print('  2. git commit -m "feat(cycling): add photos riders + logos teams + i18n FR/EN"')
    print('  3. git push')
    print()
    print("Puis sur le VPS :")
    print("  bash deploy.sh")
    print("  pm2 restart pariscore")


if __name__ == "__main__":
    main()
